// Exercise: Build a memoize utility
// 1. Write a function 'memoize' that:
//    - Takes a function 'fn' as argument
//    - Returns a new function that caches results
//    - Uses a Map for the cache, JSON.stringify(args) as key
//    - Logs 'computed' when calculating a new result
//    - Logs 'cached' when returning from cache
// 2. Create a memoized cube function: n => n * n * n
// 3. Call cube(3) twice and cube(4) twice to show caching

// Your code here

exercises.solution:
function memoize(fn) {
  const cache = new Map();
  return function (...args) {
    const key = JSON.stringify(args);
    if (cache.has(key)) {
      console.log('cached');
      return cache.get(key);
    }
    console.log('computed');
    const result = fn(...args);
    cache.set(key, result);
    return result;
  };
}

const cube = memoize((n) => n * n * n);

console.log(cube(3));
console.log(cube(3));
console.log(cube(4));
console.log(cube(4));

